+// formatRelativeTimeCV returns a human-readable relative time string for CV display.
+func formatRelativeTimeCV(timestamp string) string {
+	// Try RFC3339 format with timezone (ISO 8601)
+	t, err := time.Parse(time.RFC3339, timestamp)
+	if err != nil {
+		// Try RFC3339Nano
+		t, err = time.Parse(time.RFC3339Nano, timestamp)
+		if err != nil {
+			// Try without timezone
+			t, err = time.Parse("2006-01-02T15:04:05", timestamp)
+			if err != nil {
+				// Try alternative format
+				t, err = time.Parse("2006-01-02 15:04:05", timestamp)
+				if err != nil {
+					// Try date only
+					t, err = time.Parse("2006-01-02", timestamp)
+					if err != nil {
+						return ""
+					}
+				}
+			}
+		}
+	}
+
+	d := time.Since(t)
+	switch {
+	case d < time.Minute:
+		return "just now"
+	case d < time.Hour:
+		mins := int(d.Minutes())
+		if mins == 1 {
+			return "1m ago"
+		}
+		return fmt.Sprintf("%dm ago", mins)
+	case d < 24*time.Hour:
+		hours := int(d.Hours())
+		if hours == 1 {
+			return "1h ago"
+		}
+		return fmt.Sprintf("%dh ago", hours)
+	case d < 7*24*time.Hour:
+		days := int(d.Hours() / 24)
+		if days == 1 {
+			return "1d ago"
+		}
+		return fmt.Sprintf("%dd ago", days)
+	default:
+		weeks := int(d.Hours() / 24 / 7)
+		if weeks == 1 {
+			return "1w ago"
+		}
+		return fmt.Sprintf("%dw ago", weeks)
+	}
+}
