+// formatCountStyled formats a count with appropriate styling using lipgloss.Style.
+func formatCountStyled(count int, s lipgloss.Style) string {
+	if count == 0 {
+		return style.Dim.Render("0")
+	}
+	return s.Render(strconv.Itoa(count))
+}
